import { Component, computed, inject, signal } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { toSignal } from '@angular/core/rxjs-interop';
import { map } from 'rxjs/operators';
import { Category, Source } from '../../../core/models';

@Component({
  selector: 'app-admin-sources',
  standalone: true,
  imports: [FormsModule],
  templateUrl: './admin-sources.component.html',
  styleUrl: './admin-sources.component.css',
})
export class AdminSourcesComponent {
  // inject() (not constructor params) so these are available to field initializers below.
  private route = inject(ActivatedRoute);
  private router = inject(Router);

  // --- Backend-provided data (mock). ---
  sources = signal<Source[]>([
    {
      id: 's1',
      name: 'The Verge',
      url: 'https://www.theverge.com/rss/index.xml',
      category: 'Technology',
      categorySlug: 'tech',
      active: true,
      lastFetchedAt: this.minsAgo(4),
      lastError: null,
      articleCount: 128,
    },
    {
      id: 's2',
      name: 'Reuters Business',
      url: 'https://feeds.reuters.com/reuters/businessNews',
      category: 'Business',
      categorySlug: 'business',
      active: true,
      lastFetchedAt: this.minsAgo(4),
      lastError: null,
      articleCount: 94,
    },
    {
      id: 's3',
      name: 'BBC World',
      url: 'https://feeds.bbci.co.uk/news/world/rss.xml',
      category: 'World News',
      categorySlug: 'world',
      active: true,
      lastFetchedAt: this.minsAgo(4),
      lastError: null,
      articleCount: 156,
    },
    {
      id: 's4',
      name: 'Indie Sports Blog',
      url: 'https://indie-sports.example.com/feed',
      category: 'Sports',
      categorySlug: 'sports',
      active: true,
      lastFetchedAt: this.hoursAgo(6),
      lastError: 'Request timed out after 10s',
      articleCount: 41,
    },
    {
      id: 's5',
      name: 'Science Daily',
      url: 'https://www.sciencedaily.com/rss/all.xml',
      category: 'Science',
      categorySlug: 'science',
      active: false,
      lastFetchedAt: this.hoursAgo(30),
      lastError: '404 Not Found — feed URL may have moved',
      articleCount: 63,
    },
  ]);

  categories = signal<Category[]>([
    { id: 'c1', name: 'Technology', slug: 'tech', articleCount: 128 },
    { id: 'c2', name: 'World News', slug: 'world', articleCount: 156 },
    { id: 'c3', name: 'Business', slug: 'business', articleCount: 94 },
    { id: 'c4', name: 'Sports', slug: 'sports', articleCount: 41 },
    { id: 'c5', name: 'Science', slug: 'science', articleCount: 63 },
  ]);

  // --- Modal state driven by ?modal=add-source ---
  private modalParam = toSignal(
    this.route.queryParams.pipe(map((p) => (p['modal'] as string) ?? null)),
    { initialValue: null },
  );
  showAddModal = computed(() => this.modalParam() === 'add-source');

  // Add-source form model
  form = { name: '', url: '', category: '' };
  formError = signal<string | null>(null);
  submitting = signal(false);

  // Delete confirmation
  pendingDeleteId = signal<string | null>(null);

  openAdd(): void {
    this.formError.set(null);
    this.form = { name: '', url: '', category: this.categories()[0]?.name ?? '' };
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { modal: 'add-source' },
      queryParamsHandling: 'merge',
    });
  }

  closeModal(): void {
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { modal: null },
      queryParamsHandling: 'merge',
    });
  }

  submitAdd(): void {
    this.formError.set(null);
    const name = this.form.name.trim();
    const url = this.form.url.trim();
    const category = this.form.category;

    if (!name || !url || !category) {
      this.formError.set('All fields are required.');
      return;
    }
    // Mimic the backend's 422 URL validation (fetch + parse).
    if (!/^https?:\/\/.+\..+/.test(url)) {
      this.formError.set('422 — That URL could not be reached or is not a valid RSS/Atom feed.');
      return;
    }

    this.submitting.set(true);
    setTimeout(() => {
      const cat = this.categories().find((c) => c.name === category);
      const newSource: Source = {
        id: 's' + (this.sources().length + 1),
        name,
        url,
        category,
        categorySlug: cat?.slug ?? 'default',
        active: true,
        lastFetchedAt: null,
        lastError: null,
        articleCount: 0,
      };
      this.sources.update((list) => [newSource, ...list]);
      this.submitting.set(false);
      this.closeModal();
    }, 700);
  }

  askDelete(id: string): void {
    this.pendingDeleteId.set(id);
  }
  cancelDelete(): void {
    this.pendingDeleteId.set(null);
  }
  confirmDelete(id: string): void {
    this.sources.update((list) => list.filter((s) => s.id !== id));
    this.pendingDeleteId.set(null);
  }

  toggleActive(id: string): void {
    this.sources.update((list) =>
      list.map((s) => (s.id === id ? { ...s, active: !s.active } : s)),
    );
  }

  timeAgo(iso: string | null): string {
    if (!iso) return 'never fetched';
    const mins = Math.round((Date.now() - new Date(iso).getTime()) / 60000);
    if (mins < 1) return 'just now';
    if (mins < 60) return `${mins}m ago`;
    const hours = Math.round(mins / 60);
    if (hours < 24) return `${hours}h ago`;
    return `${Math.round(hours / 24)}d ago`;
  }

  private minsAgo(m: number): string {
    return new Date(Date.now() - m * 60_000).toISOString();
  }
  private hoursAgo(h: number): string {
    return new Date(Date.now() - h * 3_600_000).toISOString();
  }
}
